<template><div v-if="parsed" class="job-parsed"><div class="bar">Pre: {{ parsed.preMetrology.recipe }}</div><div class="group"><h4>Polisher</h4><table><tr v-for="row in parsed.polisher.rows" :key="row.label"><td>{{ row.label }}</td><td @click="emitRecipeClick(row.p1,'polishRecipe')">{{ row.p1 }}</td><td>{{ row.p2 }}</td><td>{{ row.p3 }}</td></tr></table></div><div class="group"><h4>Cleaner</h4><table><tr v-for="(row,idx) in parsed.cleaner.rows" :key="idx"><td>{{ row.index }}</td><td>{{ row.recipe }}</td></tr></table></div><div class="bar">Post: {{ parsed.postMetrology.recipe }}</div></div><div v-else>Job를 선택하세요.</div></template>
<script setup lang="ts">import type { JobParsed, JobRecipeClickPayload, RecipeSourceKind } from '../api/recipeTestApi'; const props=withDefaults(defineProps<{parsed:JobParsed|null;editable?:boolean;noneLabel?:string;missingRecipeMap?:Record<string,boolean>}>(),{editable:false,noneLabel:'(None)',missingRecipeMap:()=>({})}); const emit=defineEmits<{(e:'toggle-flag',payload:any):void;(e:'value-click',payload:JobRecipeClickPayload):void}>(); function emitRecipeClick(value:string,sourceKind:RecipeSourceKind){emit('value-click',{value,sourceKind,titleBase:'Recipe'})}</script>
<style scoped>.job-parsed{background:#d4d0c8;border:1px solid #a7a7a7;padding:8px;display:grid;gap:8px;overflow:auto}.group{background:#e6e2da;border:1px solid #8d8d8d;padding:6px}table{width:100%;border-collapse:collapse;background:#fff}td{border:1px solid #888;padding:3px}</style>
